int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  // 从 HIDDEN channel 中提取预处理行号和文件名信息
  std::string currentFilename = "0";
  std::vector<std::pair<size_t, int>> lineMarks; // (charIndex, newLine)

  auto allTokens = tokens.getTokens();
  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN) {
      std::string text = token->getText();
      if (!text.empty() && text[0] == '#') {
        // 解析 # linenum filename flags
        std::istringstream iss(text.substr(1));
        int newLine = 0;
        std::string fname;
        iss >> newLine >> fname;
        if (!fname.empty() && fname[0] == '"') {
          // 去掉引号
          fname = fname.substr(1, fname.length() - 2);
        }
        if (!fname.empty()) {
          currentFilename = fname;
        }
        if (newLine > 0) {
          lineMarks.push_back({token->getStartIndex(), newLine});
        }
      }
    }
  }

  // 解析每个 token 的行号、列号、StartOfLine 和 LeadingSpace
  auto computeLoc = [&](size_t startIdx, size_t stopIdx) -> std::tuple<std::string, int, int, bool, bool> {
    // 从开头到 startIdx 计算行和列
    std::string source = input.toString();
    int line = 1;
    int col = 1;
    std::string filename = currentFilename;

    bool startOfLine = true;
    bool leadingSpace = false;

    // 检查 startIdx 之前的字符
    if (startIdx > 0) {
      char prev = source[startIdx - 1];
      if (prev == ' ' || prev == '\t') {
        startOfLine = false;
        leadingSpace = true;
      } else if (prev == '\n' || prev == '\r') {
        startOfLine = true;
        leadingSpace = false;
      } else {
        startOfLine = false;
        leadingSpace = false;
      }
    }

    size_t lastNewline = std::string::npos;
    for (size_t i = 0; i < startIdx; i++) {
      char c = source[i];
      if (c == '\n') {
        line++;
        col = 0;
        lastNewline = i;
      } else if (c == '\r') {
        line++;
        col = 0;
        lastNewline = i;
        if (i + 1 < startIdx && source[i + 1] == '\n')
          i++;
      }
      col++;
    }

    // 重新计算 col：从最后一个换行符后的位置开始算
    col = 1;
    if (lastNewline != std::string::npos) {
      for (size_t i = lastNewline + 1; i < startIdx; i++) {
        col++;
      }
    } else {
      col = 1;
      for (size_t i = 0; i < startIdx; i++) {
        col++;
      }
    }

    // 处理 # 行号插入：source 中有 # marker 行，这些行不应影响源码行的计数
    // 从 tokens 重新计算行号
    // 实际上应该用 input 的原始行号计算，同时考虑 # marker

    // 简化处理：只用 source 行号
    // 我们需要 columns 从1开始
    col = startIdx == 0 ? 1 : static_cast<int>(startIdx);
    for (size_t i = startIdx; i > 0; i--) {
      if (source[i - 1] == '\n' || (source[i - 1] == '\r' && (i < 2 || source[i - 2] != '\n'))) {
        col = static_cast<int>(startIdx - i + 1);
        break;
      }
    }

    return {filename, line, col, startOfLine, leadingSpace};
  };

  // 重新按照源码行号计算（跳过 # 行和 <built-in> 行）
  // 我们需要使用 input source 逐字计算

  // 为简单起见，我们逐个遍历所有非 hidden token，在输出时计算其位置

  // 更好的方式：遍历 source 计算每个 token 的位置
  // 首先将 source 按行切分，跳过 # 行

  int actualLine = 0;
  std::string actualFile = "";
  std::vector<int> tokenLines; // 每个 token 对应的实际行号

  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN) {
      std::string text = token->getText();
      if (!text.empty() && text[0] == '#') {
        std::istringstream iss(text.substr(1));
        int nl;
        std::string fn;
        iss >> nl >> fn;
        if (!fn.empty() && fn[0] == '"') {
          fn = fn.substr(1, fn.length() - 2);
        }
        if (!fn.empty()) {
          actualFile = fn;
        }
        if (nl > 0) {
          actualLine = nl - 1; // 下一行是 nl
        }
      } else if (!text.empty() && (text[0] == '\n' || text[0] == '\r')) {
        actualLine++;
      }
    } else if (token->getType() != antlr4::Token::EOF) {
      actualLine++; // 真实 token 在行上
      // 更好的做法是计算到底有多少个换行，但这里先简化
    }
  }

  // 让我们采用不同的策略：直接遍历 source 字符串，构建每个字符对应的行号、列号、文件名的映射
  std::string source = input.toString();
  std::vector<int> charLine(source.size() + 1, 1);
  std::vector<int> charCol(source.size() + 1, 1);
  std::vector<std::string> charFile(source.size() + 1, "0");

  int curLine = 1;
  int curCol = 1;
  std::string curFile = "0";

  size_t i = 0;
  while (i < source.size()) {
    charFile[i] = curFile;
    charLine[i] = curLine;
    charCol[i] = curCol;

    // 检查是否是 # marker 行
    if (source[i] == '#' && (i == 0 || source[i - 1] == '\n' || source[i - 1] == '\r')) {
      // 读取整行
      size_t end = source.find('\n', i);
      if (end == std::string::npos) end = source.size();
      std::string line = source.substr(i, end - i);
      std::istringstream iss(line.substr(1));
      int nl = 0;
      std::string fn;
      iss >> nl >> fn;
      if (!fn.empty() && fn[0] == '"') {
        fn = fn.substr(1, fn.length() - 2);
      }
      if (!fn.empty()) curFile = fn;
      if (nl > 0) {
        curLine = nl - 1; // 下一行行号是 nl
      }
      // 跳过该行
      i = end + 1;
      curCol = 1;
      if (nl > 0) {
        curLine = nl;
      }
      continue;
    }

    if (source[i] == '\r') {
      if (i + 1 < source.size() && source[i + 1] == '\n') {
        i++;
      }
      curLine++;
      curCol = 1;
      i++;
      continue;
    }
    if (source[i] == '\n') {
      curLine++;
      curCol = 1;
      i++;
      continue;
    }

    curCol++;
    i++;
  }
  // 末尾位置
  charFile[source.size()] = curFile;
  charLine[source.size()] = curLine;
  charCol[source.size()] = curCol;

  // 现在遍历 allTokens 输出
  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN)
      continue;

    size_t startIdx = token->getStartIndex();
    int line = charLine[startIdx];
    int col = charCol[startIdx];
    std::string filename = charFile[startIdx];

    bool startOfLine = false;
    bool leadingSpace = false;

    if (startIdx == 0) {
      startOfLine = true;
    } else {
      char prev = source[startIdx - 1];
      if (prev == '\n' || prev == '\r') {
        startOfLine = true;
      } else if (prev == ' ' || prev == '\t') {
        leadingSpace = true;
      }
    }

    // 对于 EOF token
    if (token->getType() == antlr4::Token::EOF) {
      // eof 行号列号为最后一个 token 行号，列号 + 1
      size_t lastIdx = source.size();
      line = charLine[lastIdx];
      col = charCol[lastIdx];
      filename = charFile[lastIdx];
      startOfLine = false;
      leadingSpace = false;
    }

    print_token(token, tokens, outFile, lexer, filename, line, col,
                startOfLine, leadingSpace);
  }
}

