   267	      ->getType()) {
   268	    case ast::Plus:
   269	      ret->op = ret->kPos;
   270	      break;
   271	
   272	    case ast::Minus:
   273	      ret->op = ret->kNeg;
   274	      break;
   275	
   276	    default:
   277	      ABORT();
   278	  }
   279	
   280	  ret->sub = self(ctx->unaryExpression());
   281	
   282	  return ret;
   283	}
   284	
   285	Expr*
   286	Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
   287	{
   288	  auto children = ctx->children;
   289	  auto sub = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));
   290	  return sub;
   291	}
   292	
   293	Expr*
   294	Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
   295	{
   296	
   297	  if (auto p = ctx->Identifier()) {
   298	    auto name = p->getText();
   299	    auto ret = make<DeclRefExpr>();
   300	    ret->decl = mSymtbl->resolve(name);
   301	    return ret;
   302	  }
   303	
   304	  if (auto p = ctx->Constant()) {
   305	    auto text = p->getText();
   306	
   307	    auto ret = make<IntegerLiteral>();
   308	
   309	    ASSERT(!text.empty());
   310	    if (text[0] != '0')
   311	      ret->val = std::stoll(text);
   312	
   313	    else if (text.size() == 1)
   314	      ret->val = 0;
   315	
   316	    else if (text[1] == 'x' || text[1] == 'X')
   317	      ret->val = std::stoll(text.substr(2), nullptr, 16);
   318	
   319	    else
   320	      ret->val = std::stoll(text.substr(1), nullptr, 8);
   321	
   322	    return ret;
   323	  }
   324	
   325	  ABORT();
   326	}
   327	
   328	Expr*
   329	Ast2Asg::operator()(ast::InitializerContext* ctx)
   330	{
   331	  if (auto p = ctx->assignmentExpression())
   332	    return self(p);
   333	
   334	  auto ret = make<InitListExpr>();
   335	
   336	  if (auto p = ctx->initializerList()) {
   337	    for (auto&& i : p->initializer()) {
   338	      // 将初始化列表展平
   339	      auto expr = self(i);
   340	      if (auto p = expr->dcst<InitListExpr>()) {
   341	        for (auto&& sub : p->list)
   342	          ret->list.push_back(sub);
   343	      } else {
   344	        ret->list.push_back(expr);
   345	      }
   346	    }
   347	  }
   348	
   349	  return ret;
   350	}
