   352	//==============================================================================
   353	// 语句
   354	//==============================================================================
   355	
   356	Stmt*
   357	Ast2Asg::operator()(ast::StatementContext* ctx)
   358	{
   359	  if (auto p = ctx->compoundStatement())
   360	    return self(p);
   361	
   362	  if (auto p = ctx->expressionStatement())
   363	    return self(p);
   364	
   365	  if (auto p = ctx->jumpStatement())
   366	    return self(p);
   367	
   368	  ABORT();
   369	}
   370	
   371	CompoundStmt*
   372	Ast2Asg::operator()(ast::CompoundStatementContext* ctx)
   373	{
   374	  auto ret = make<CompoundStmt>();
   375	
   376	  if (auto p = ctx->blockItemList()) {
   377	    Symtbl localDecls(self);
   378	
   379	    for (auto&& i : p->blockItem()) {
   380	      if (auto q = i->declaration()) {
   381	        auto sub = make<DeclStmt>();
   382	        sub->decls = self(q);
   383	        ret->subs.push_back(sub);
   384	      }
   385	
   386	      else if (auto q = i->statement())
   387	        ret->subs.push_back(self(q));
   388	
   389	      else
   390	        ABORT();
   391	    }
   392	  }
   393	
   394	  return ret;
   395	}
   396	
   397	Stmt*
   398	Ast2Asg::operator()(ast::ExpressionStatementContext* ctx)
   399	{
   400	  if (auto p = ctx->expression()) {
   401	    auto ret = make<ExprStmt>();
   402	    ret->expr = self(p);
   403	    return ret;
   404	  }
   405	
   406	  return make<NullStmt>();
   407	}
   408	
   409	Stmt*
   410	Ast2Asg::operator()(ast::JumpStatementContext* ctx)
   411	{
   412	  if (ctx->Return()) {
   413	    auto ret = make<ReturnStmt>();
   414	    ret->func = mCurrentFunc;
   415	    if (auto p = ctx->expression())
   416	      ret->expr = self(p);
   417	    return ret;
   418	  }
   419	
   420	  ABORT();
   421	}
