      ret = node;
      continue;
    }

    // 数组下标
    if (ctx->LeftBracket(i - 1)) {
      auto node = make<BinaryExpr>();
      node->op = node->kIndex;
      node->lft = ret;

      // 找到对应的 expression
      for (unsigned j = i; j < children.size(); ++j) {
        if (auto exprCtx = dynamic_cast<ast::ExpressionContext*>(children[j])) {
          node->rht = self(exprCtx);
          i = j;
          break;
        }
      }

      ret = node;
      continue;
    }
  }

  return ret;
}

