   196	        llvm::Register vreg = newVReg();
   197	        valueVReg_[&inst] = vreg;
   198	        vregSpill_[vreg] = off;
   199	        off += 8;
   200	      }
   201	    }
   202	
   203	    // Stack storage for allocas.
   204	    for (const llvm::BasicBlock& bb : f) {
