   403	  // 翻译 GEP：从基址出发，按元素步长不断累加偏移，得到最终地址。
   404	  void emitGEPInst(const llvm::GetElementPtrInst& gi)
   405	  {
   406	    llvm::Register dst = vregOf(&gi);
   407	    llvm::Register base = emitLoadValue(gi.getPointerOperand());
   408	    emitVMov(dst, base);
   409	
   410	    int64_t constOff = 0;
   411	    auto typeIt = llvm::gep_type_begin(gi);
   412	    auto idxIt = gi.idx_begin();
   413	    for (; typeIt != llvm::gep_type_end(gi); ++typeIt, ++idxIt) {
   414	      if (typeIt.isStruct())
   415	        llvm::report_fatal_error("struct GEP not supported in rv64-min backend");
   416	      int64_t stride = static_cast<int64_t>(
   417	          typeIt.getSequentialElementStride(dl_).getFixedValue());
   418	      const auto* idxC = llvm::dyn_cast<llvm::ConstantInt>(*idxIt);
   419	      if (idxC) {
   420	        constOff += idxC->getSExtValue() * stride;
   421	        continue;
   422	      }
   423	      if (constOff != 0) {
   424	        emitVAddImm(dst, dst, constOff);
   425	        constOff = 0;
   426	      }
   427	      llvm::Register idxReg = emitLoadValue(*idxIt);
   428	      llvm::Register scale = nextTempVReg();
   429	      emitVLoadImm(scale, stride);
   430	      emitVMul(scale, idxReg, scale);
   431	      emitVAdd(dst, dst, scale);
   432	    }
   433	
   434	    if (constOff != 0)
   435	      emitVAddImm(dst, dst, constOff);
   436	  }
