   439	// 输出全局变量的数据段/零初始化段。
   440	static void emitGlobals(const llvm::Module& m, RvAsmEmitter& as)
   441	{
   442	  const llvm::DataLayout& dl = m.getDataLayout();
   443	
   444	  for (const llvm::GlobalVariable& gv : m.globals()) {
   445	    if (gv.isDeclaration())
   446	      continue;
   447	
   448	    std::string name = gv.getName().str();
   449	    if (name.empty())
   450	      continue;
   451	
   452	    uint64_t size = dl.getTypeAllocSize(gv.getValueType());
   453	
   454	    if (gv.hasInitializer() && gv.getInitializer()->isZeroValue()) {
   455	      as.emitDirective("\t.bss");
   456	      if (gv.hasExternalLinkage())
   457	        as.emitDirective("\t.globl " + name);
   458	      as.emitDirective("\t.align 3");
   459	      as.emitLabel(name);
   460	      as.emitDirective("\t.zero " + std::to_string(size));
   461	      continue;
   462	    }
   463	
   464	    as.emitDirective("\t.data");
   465	    if (gv.hasExternalLinkage())
   466	      as.emitDirective("\t.globl " + name);
   467	    as.emitDirective("\t.align 3");
   468	    as.emitLabel(name);
   469	
   470	    const llvm::Constant* init = gv.hasInitializer() ? gv.getInitializer() : nullptr;
   471	    if (!init) {
   472	      as.emitDirective("\t.zero " + std::to_string(size));
   473	      continue;
   474	    }
   475	
   476	    auto emitInit = [&](const llvm::Constant* c, auto&& emitInitRef) -> void {
   477	      if (c->isZeroValue()) {
   478	        as.emitDirective("\t.zero " + std::to_string(dl.getTypeAllocSize(c->getType())));
   479	        return;
   480	      }
   481	      if (const auto* ci = llvm::dyn_cast<llvm::ConstantInt>(c)) {
   482	        uint64_t sz = dl.getTypeAllocSize(ci->getType());
   483	        if (sz == 4) {
   484	          as.emitDirective("\t.word " + std::to_string(ci->getSExtValue()));
   485	        } else if (sz == 8) {
   486	          as.emitDirective("\t.quad " + std::to_string(ci->getSExtValue()));
   487	        } else if (sz == 1) {
   488	          as.emitDirective("\t.byte " + std::to_string(ci->getZExtValue()));
   489	        } else {
   490	          as.emitDirective("\t.zero " + std::to_string(sz));
   491	        }
   492	        return;
   493	      }
   494	      if (const auto* ca = llvm::dyn_cast<llvm::ConstantArray>(c)) {
   495	        for (unsigned i = 0; i < ca->getNumOperands(); ++i) {
   496	          emitInitRef(llvm::cast<llvm::Constant>(ca->getOperand(i)), emitInitRef);
   497	        }
   498	        return;
   499	      }
   500	      if (const auto* cda = llvm::dyn_cast<llvm::ConstantDataArray>(c)) {
   501	        for (unsigned i = 0; i < cda->getNumElements(); ++i) {
   502	          emitInitRef(cda->getElementAsConstant(i), emitInitRef);
   503	        }
   504	        return;
   505	      }
   506	      as.emitDirective("\t.zero " + std::to_string(dl.getTypeAllocSize(c->getType())));
   507	    };
   508	
   509	    emitInit(init, emitInit);
   510	  }
   511	}
