     5	PreservedAnalyses
     6	ConstantFolding::run(Module& mod, ModuleAnalysisManager& mam)
     7	{
     8	  int constFoldTimes = 0;
     9	
    10	  // 遍历所有函数
    11	  for (auto& func : mod) {
    12	    // 遍历每个函数的基本块
    13	    for (auto& bb : func) {
    14	      std::vector<Instruction*> instToErase;
    15	      // 遍历每个基本块的指令
    16	      for (auto& inst : bb) {
    17	        // 判断当前指令是否是二元运算指令
    18	        if (auto binOp = dyn_cast<BinaryOperator>(&inst)) {
    19	          // 获取二元运算指令的左右操作数，并尝试转换为常整数
    20	          Value* lhs = binOp->getOperand(0);
    21	          Value* rhs = binOp->getOperand(1);
    22	          auto constLhs = dyn_cast<ConstantInt>(lhs);
    23	          auto constRhs = dyn_cast<ConstantInt>(rhs);
    24	          switch (binOp->getOpcode()) {
    25	            case Instruction::Add: {
    26	              // 若左右操作数均为整数常量，则进行常量折叠与use替换
    27	              if (constLhs && constRhs) {
    28	                binOp->replaceAllUsesWith(ConstantInt::getSigned(
    29	                  binOp->getType(),
    30	                  constLhs->getSExtValue() + constRhs->getSExtValue()));
    31	                instToErase.push_back(binOp);
    32	                ++constFoldTimes;
    33	              }
    34	              break;
    35	            }
    36	            case Instruction::Sub: {
    37	              if (constLhs && constRhs) {
    38	                binOp->replaceAllUsesWith(ConstantInt::getSigned(
    39	                  binOp->getType(),
    40	                  constLhs->getSExtValue() - constRhs->getSExtValue()));
    41	                instToErase.push_back(binOp);
    42	                ++constFoldTimes;
    43	              }
    44	              break;
    45	            }
    46	            case Instruction::Mul: {
    47	              if (constLhs && constRhs) {
    48	                binOp->replaceAllUsesWith(ConstantInt::getSigned(
    49	                  binOp->getType(),
    50	                  constLhs->getSExtValue() * constRhs->getSExtValue()));
    51	                instToErase.push_back(binOp);
    52	                ++constFoldTimes;
    53	              }
    54	              break;
    55	            }
    56	            case Instruction::UDiv:
    57	            case Instruction::SDiv: {
    58	              if (constLhs && constRhs) {
    59	                binOp->replaceAllUsesWith(ConstantInt::getSigned(
    60	                  binOp->getType(),
    61	                  constLhs->getSExtValue() / constRhs->getSExtValue()));
    62	                instToErase.push_back(binOp);
    63	                ++constFoldTimes;
    64	              }
    65	              break;
    66	            }
    67	            default:
    68	              break;
    69	          }
    70	        }
    71	      }
    72	      // 统一删除被折叠为常量的指令
    73	      for (auto& i : instToErase)
    74	        i->eraseFromParent();
    75	    }
    76	  }
