   268	        // Okay, we found a load before a store to the alloca.  It is actually
   269	        // live into this block.
   270	        if (LI->getOperand(0) == AI)
   271	          break;
   272	    }
   273	  }
   274	
   275	  // Now that we have a set of blocks where the phi is live-in, recursively add
   276	  // their predecessors until we find the full region the value is live.
   277	  while (!LiveInBlockWorklist.empty()) {
   278	    BasicBlock* BB = LiveInBlockWorklist.pop_back_val();
   279	
   280	    // The block really is live in here, insert it into the set.  If already in
   281	    // the set, then it has already been processed.
   282	    if (!LiveInBlocks.insert(BB).second)
   283	      continue;
   284	
   285	    // Since the value is live into BB, it is either defined in a predecessor or
   286	    // live into it to.  Add the preds to the worklist unless they are a
   287	    // defining block.
   288	    for (BasicBlock* P : predecessors(BB)) {
   289	      // The value is not live into a predecessor if it defines the value.
   290	      if (DefBlocks.count(P))
   291	        continue;
   292	
   293	      // Otherwise it is, add to the worklist.
   294	      LiveInBlockWorklist.push_back(P);
   295	    }
   296	  }
   297	}
   298	
   299	/// Queue a phi-node to be added to a basic-block for a specific Alloca.
   300	///
   301	/// Returns true if there wasn't already a phi-node for that variable
   302	bool
   303	PromoteMem2Reg::QueuePhiNode(BasicBlock* BB,
   304	                             unsigned AllocaNo,
   305	                             unsigned& Version)
   306	{
   307	  // Look up the basic-block in question.
   308	  PHINode*& PN = NewPhiNodes[std::make_pair(BBNumbers[BB], AllocaNo)];
   309	
   310	  // If the BB already has a phi node added for the i'th alloca then we're done!
   311	  if (PN)
   312	    return false;
   313	
   314	  // Create a PhiNode using the dereferenced type... and add the phi-node to the
   315	  // BasicBlock.
   316	  PN = PHINode::Create(Allocas[AllocaNo]->getAllocatedType(),
   317	                       getNumPreds(BB),
   318	                       Allocas[AllocaNo]->getName() + "." + Twine(Version++));
   319	  PN->insertBefore(&*(BB->begin()));
   320	  PhiToAllocaMap[PN] = AllocaNo;
   321	  return true;
   322	}
   323	
   324	/// Recursively traverse the CFG of the function, renaming loads and
   325	/// stores to the allocas which we are promoting.
   326	///
   327	/// IncomingVals indicates what value each Alloca contains on exit from the
   328	/// predecessor block Pred.
   329	void
   330	PromoteMem2Reg::RenamePass(BasicBlock* BB,
   331	                           BasicBlock* Pred,
   332	                           RenamePassData::ValVector& IncomingVals,
   333	                           std::vector<RenamePassData>& Worklist)
   334	{
   335	NextIteration:
   336	  // If we are inserting any phi nodes into this BB, they will already be in the
   337	  // block.
   338	  if (PHINode* APN = dyn_cast<PHINode>(BB->begin())) {
   339	    // If we have PHI nodes to update, compute the number of edges from Pred to
   340	    // BB.
   341	    if (PhiToAllocaMap.count(APN)) {
   342	      // We want to be able to distinguish between PHI nodes being inserted by
   343	      // this invocation of mem2reg from those phi nodes that already existed in
   344	      // the IR before mem2reg was run.  We determine that APN is being inserted
   345	      // because it is missing incoming edges.  All other PHI nodes being
   346	      // inserted by this pass of mem2reg will have the same number of incoming
   347	      // operands so far.  Remember this count.
   348	      unsigned NewPHINumOperands = APN->getNumOperands();
   349	
   350	      unsigned NumEdges = llvm::count(successors(Pred), BB);
   351	      assert(NumEdges && "Must be at least one edge from Pred to BB!");
   352	
   353	      // Add entries for all the phis.
   354	      BasicBlock::iterator PNI = BB->begin();
   355	      do {
   356	        unsigned AllocaNo = PhiToAllocaMap[APN];
   357	
   358	        // Add N incoming values to the PHI node.
   359	        for (unsigned i = 0; i != NumEdges; ++i)
   360	          APN->addIncoming(IncomingVals[AllocaNo], Pred);
   361	
   362	        // The currently active variable for this block is now the PHI.
   363	        IncomingVals[AllocaNo] = APN;
   364	
   365	        // Get the next phi node.
   366	        ++PNI;
   367	        APN = dyn_cast<PHINode>(PNI);
   368	        if (!APN)
   369	          break;
   370	
   371	        // Verify that it is missing entries.  If not, it is not being inserted
   372	        // by this mem2reg invocation so we want to ignore it.
   373	      } while (APN->getNumOperands() == NewPHINumOperands);
   374	    }
   375	  }
   376	
   377	  // Don't revisit blocks.
   378	  if (!Visited.insert(BB).second)
   379	    return;
   380	
   381	  for (BasicBlock::iterator II = BB->begin(); !II->isTerminator();) {
   382	    Instruction* I = &*II++; // get the instruction, increment iterator
   383	
   384	    if (LoadInst* LI = dyn_cast<LoadInst>(I)) {
   385	      AllocaInst* Src = dyn_cast<AllocaInst>(LI->getPointerOperand());
   386	      if (!Src)
   387	        continue;
   388	
   389	      DenseMap<AllocaInst*, unsigned>::iterator AI = AllocaLookup.find(Src);
   390	      if (AI == AllocaLookup.end())
   391	        continue;
   392	
   393	      Value* V = IncomingVals[AI->second];
   394	
   395	      // Anything using the load now uses the current value.
   396	      LI->replaceAllUsesWith(V);
   397	      LI->eraseFromParent();
   398	    } else if (StoreInst* SI = dyn_cast<StoreInst>(I)) {
   399	      // Delete this instruction and mark the name as the current holder of the
   400	      // value
   401	      AllocaInst* Dest = dyn_cast<AllocaInst>(SI->getPointerOperand());
   402	      if (!Dest)
   403	        continue;
   404	
   405	      DenseMap<AllocaInst*, unsigned>::iterator ai = AllocaLookup.find(Dest);
   406	      if (ai == AllocaLookup.end())
   407	        continue;
   408	
   409	      // what value were we writing?
   410	      unsigned AllocaNo = ai->second;
   411	      IncomingVals[AllocaNo] = SI->getOperand(0);
   412	
   413	      SI->eraseFromParent();
   414	    }
   415	  }
   416	
   417	  // 'Recurse' to our successors.
   418	  succ_iterator I = succ_begin(BB), E = succ_end(BB);
   419	  if (I == E)
   420	    return;
   421	
   422	  // Keep track of the successors so we don't visit the same successor twice
   423	  SmallPtrSet<BasicBlock*, 8> VisitedSuccs;
   424	
   425	  // Handle the first successor without using the worklist.
   426	  VisitedSuccs.insert(*I);
   427	  Pred = BB;
   428	  BB = *I;
   429	  ++I;
   430	
   431	  for (; I != E; ++I)
   432	    if (VisitedSuccs.insert(*I).second)
   433	      Worklist.emplace_back(*I, Pred, IncomingVals);
   434	
   435	  goto NextIteration;
   436	}
   437	
   438	static void
   439	PromoteMemToReg(ArrayRef<AllocaInst*> Allocas, DominatorTree& DT)
   440	{
   441	  // If there is nothing to do, bail out...
   442	  if (Allocas.empty())
   443	    return;
   444	
   445	  PromoteMem2Reg(Allocas, DT).run();
   446	}
   447	
   448	static bool
   449	promoteMemoryToRegister(Function& F, DominatorTree& DT)
   450	{
   451	  std::vector<AllocaInst*> Allocas;
   452	  BasicBlock& BB = F.getEntryBlock(); // Get the entry node for the function
   453	  bool Changed = false;
   454	
   455	  while (true) {
   456	    Allocas.clear();
   457	
   458	    // Find allocas that are safe to promote, by looking at all instructions in
   459	    // the entry node
   460	    for (BasicBlock::iterator I = BB.begin(), E = --BB.end(); I != E; ++I)
   461	      if (AllocaInst* AI = dyn_cast<AllocaInst>(I)) // Is it an alloca?
   462	        if (isAllocaPromotable(AI))
   463	          Allocas.push_back(AI);
   464	
   465	    if (Allocas.empty())
   466	      break;
   467	
   468	    PromoteMemToReg(Allocas, DT);
   469	    Changed = true;
   470	  }
   471	  return Changed;
   472	}
   473	
   474	PreservedAnalyses
   475	Mem2Reg::run(llvm::Module& mod, llvm::ModuleAnalysisManager& mam)
   476	{
   477	
   478	  FunctionAnalysisManager fam;
   479	  PassBuilder pb;
   480	  pb.registerFunctionAnalyses(fam);
   481	  bool flag = true;
   482	  for (Function& func : mod) {
   483	    if (func.isDeclaration())
   484	      continue;
   485	    auto& DT = fam.getResult<DominatorTreeAnalysis>(func);
   486	    if (promoteMemoryToRegister(func, DT)) {
   487	      flag = false;
   488	    }
   489	  }
   490	  if (flag) {
   491	    return PreservedAnalyses::all();
   492	  }
   493	  PreservedAnalyses PA;
   494	  PA.preserveSet<CFGAnalyses>();
   495	  return PA;
   496	}
